#ifndef GQA_PAGED_DECODE_H32_KV4_D128_PS1_KERNEL_H_
#define GQA_PAGED_DECODE_H32_KV4_D128_PS1_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>

// Fixed compile-time constants
constexpr int kNumQOHeads = 32;
constexpr int kNumKVHeads = 4;
constexpr int kHeadDim    = 128;
constexpr int kPageSize   = 1;
constexpr int kGQARatio   = kNumQOHeads / kNumKVHeads; // 8

void LaunchGQAPagedDecodeH32KV4D128PS1(
    const void* q_bf16,          // [B, 32, 128]
    const void* k_cache_bf16,    // [num_pages, 1, 4, 128]
    const void* v_cache_bf16,    // [num_pages, 1, 4, 128]
    const int32_t* kv_indptr,    // [B+1]
    const int32_t* kv_indices,   // [kv_indptr[B]]
    int32_t batch_size,
    int32_t num_pages,
    float sm_scale,
    void* out_bf16,              // [B, 32, 128]
    float* lse_out,              // [B, 32] base-2 LSE
    cudaStream_t stream);

#endif  // GQA_PAGED_DECODE_H32_KV4_D128_PS1_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>

#include <cstdint>
#include <cmath>

#if !defined(__CUDA_ARCH__) || (__CUDA_ARCH__ >= 700)
#define LDG(x) __ldg(x)
#else
#define LDG(x) (*(x))
#endif

static __device__ __forceinline__ float bf16_to_f32(__nv_bfloat16 x) {
  return __bfloat162float(x);
}
static __device__ __forceinline__ __nv_bfloat16 f32_to_bf16_rn(float x) {
  return __float2bfloat16_rn(x);
}

static __device__ __forceinline__ float warp_sum(float v) {
#pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(0xffffffff, v, offset);
  }
  return v;
}

// blockDim.x must be 128
static __device__ __forceinline__ float block_sum_128(float v) {
  __shared__ float smem[4]; // 4 warps
  int lane = threadIdx.x & 31;
  int wid  = threadIdx.x >> 5;

  v = warp_sum(v);
  if (lane == 0) smem[wid] = v;
  __syncthreads();

  float x = 0.0f;
  if (wid == 0) {
    x = (lane < 4) ? smem[lane] : 0.0f;
    x = warp_sum(x);
  }
  x = __shfl_sync(0xffffffff, x, 0);
  return x;
}

static __device__ __forceinline__ int64_t kv_offset_ps1(int32_t page, int32_t kvh, int32_t d) {
  // k_cache/v_cache contiguous layout: [num_pages, 1, 4, 128]
  // flatten over page_size=1 => index = ((page * 4 + kvh) * 128 + d)
  return (static_cast<int64_t>(page) * kNumKVHeads + kvh) * kHeadDim + d;
}
static __device__ __forceinline__ int64_t q_offset(int32_t b, int32_t h, int32_t d) {
  return (static_cast<int64_t>(b) * kNumQOHeads + h) * kHeadDim + d;
}
static __device__ __forceinline__ int64_t out_offset(int32_t b, int32_t h, int32_t d) {
  return (static_cast<int64_t>(b) * kNumQOHeads + h) * kHeadDim + d;
}
static __device__ __forceinline__ int64_t lse_offset(int32_t b, int32_t h) {
  return static_cast<int64_t>(b) * kNumQOHeads + h;
}

// One block per (b,h), 128 threads (one per d).
// Online softmax (streaming) to avoid storing logits/attn.
__global__ void gqa_paged_decode_h32_kv4_d128_ps1_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k_cache,
    const __nv_bfloat16* __restrict__ v_cache,
    const int32_t* __restrict__ kv_indptr,
    const int32_t* __restrict__ kv_indices,
    int32_t batch_size,
    int32_t num_pages,
    float sm_scale,
    __nv_bfloat16* __restrict__ out,
    float* __restrict__ lse_out) {

  const int32_t b = static_cast<int32_t>(blockIdx.x);
  const int32_t h = static_cast<int32_t>(blockIdx.y);
  const int32_t d = static_cast<int32_t>(threadIdx.x);

  if (b >= batch_size || h >= kNumQOHeads || d >= kHeadDim) return;

  const int32_t page_start = LDG(kv_indptr + b);
  const int32_t page_end   = LDG(kv_indptr + b + 1);
  const int32_t n_tokens   = page_end - page_start;

  if (n_tokens <= 0) {
    out[out_offset(b, h, d)] = f32_to_bf16_rn(0.0f);
    if (d == 0) lse_out[lse_offset(b, h)] = -INFINITY;
    return;
  }

  const int32_t kvh = h / kGQARatio;
  const float qd = bf16_to_f32(LDG(q + q_offset(b, h, d)));

  float m = -INFINITY; // running max
  float s = 0.0f;      // running sum exp(logit - m)
  float out_acc = 0.0f;

  // Iterate tokens (pages) for page_size=1
  for (int t = 0; t < n_tokens; ++t) {
    const int32_t page = LDG(kv_indices + (page_start + t));
    if ((uint32_t)page >= (uint32_t)num_pages) continue;

    const float kd = bf16_to_f32(LDG(k_cache + kv_offset_ps1(page, kvh, d)));
    const float dot = block_sum_128(qd * kd);
    const float logit = dot * sm_scale;

    const float m_new = fmaxf(m, logit);
    const float alpha = (m == -INFINITY) ? 0.0f : __expf(m - m_new);
    const float beta  = __expf(logit - m_new);

    s = s * alpha + beta;

    const float vd = bf16_to_f32(LDG(v_cache + kv_offset_ps1(page, kvh, d)));
    out_acc = out_acc * alpha + beta * vd;

    m = m_new;
  }

  if (!(s > 0.0f) || !isfinite(m)) {
    out[out_offset(b, h, d)] = f32_to_bf16_rn(0.0f);
    if (d == 0) lse_out[lse_offset(b, h)] = -INFINITY;
    return;
  }

  out[out_offset(b, h, d)] = f32_to_bf16_rn(out_acc / s);

  if (d == 0) {
    constexpr float inv_ln2 = 1.4426950408889634f; // 1/log(2)
    lse_out[lse_offset(b, h)] = (m + logf(s)) * inv_ln2;
  }
}

void LaunchGQAPagedDecodeH32KV4D128PS1(
    const void* q_bf16,
    const void* k_cache_bf16,
    const void* v_cache_bf16,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    int32_t batch_size,
    int32_t num_pages,
    float sm_scale,
    void* out_bf16,
    float* lse_out,
    cudaStream_t stream) {

  dim3 block(128, 1, 1);
  dim3 grid(static_cast<unsigned>(batch_size),
            static_cast<unsigned>(kNumQOHeads),
            1);

  gqa_paged_decode_h32_kv4_d128_ps1_kernel<<<grid, block, 0, stream>>>(
      reinterpret_cast<const __nv_bfloat16*>(q_bf16),
      reinterpret_cast<const __nv_bfloat16*>(k_cache_bf16),
      reinterpret_cast<const __nv_bfloat16*>(v_cache_bf16),
      kv_indptr,
      kv_indices,
      batch_size,
      num_pages,
      sm_scale,
      reinterpret_cast<__nv_bfloat16*>(out_bf16),
      lse_out);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDAGuard.h>

#include <cmath>
#include <sstream>
#include <stdexcept>
#include <vector>

#include "kernel.h"

static void check_cuda_contig(const torch::Tensor& t, const char* name) {
  if (!t.defined()) {
    std::ostringstream oss; oss << name << " is undefined";
    throw std::invalid_argument(oss.str());
  }
  if (!t.device().is_cuda()) {
    std::ostringstream oss; oss << name << " must be a CUDA tensor";
    throw std::invalid_argument(oss.str());
  }
  if (!t.is_contiguous()) {
    std::ostringstream oss; oss << name << " must be contiguous";
    throw std::invalid_argument(oss.str());
  }
}

static void check_dtype(const torch::Tensor& t, c10::ScalarType dt, const char* name) {
  if (t.scalar_type() != dt) {
    std::ostringstream oss;
    oss << name << " must have dtype " << c10::toString(dt)
        << " but got " << c10::toString(t.scalar_type());
    throw std::invalid_argument(oss.str());
  }
}

std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k_cache,
    torch::Tensor v_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    c10::optional<double> sm_scale_opt) {

  check_cuda_contig(q, "q");
  check_cuda_contig(k_cache, "k_cache");
  check_cuda_contig(v_cache, "v_cache");
  check_cuda_contig(kv_indptr, "kv_indptr");
  check_cuda_contig(kv_indices, "kv_indices");

  check_dtype(q, c10::ScalarType::BFloat16, "q");
  check_dtype(k_cache, c10::ScalarType::BFloat16, "k_cache");
  check_dtype(v_cache, c10::ScalarType::BFloat16, "v_cache");
  check_dtype(kv_indptr, c10::ScalarType::Int, "kv_indptr");
  check_dtype(kv_indices, c10::ScalarType::Int, "kv_indices");

  if (q.dim() != 3) throw std::invalid_argument("q must be rank-3 [B,32,128]");
  if (k_cache.dim() != 4) throw std::invalid_argument("k_cache must be rank-4 [num_pages,1,4,128]");
  if (v_cache.dim() != 4) throw std::invalid_argument("v_cache must be rank-4 [num_pages,1,4,128]");
  if (kv_indptr.dim() != 1) throw std::invalid_argument("kv_indptr must be rank-1 [B+1]");
  if (kv_indices.dim() != 1) throw std::invalid_argument("kv_indices must be rank-1 [num_kv_indices]");

  const int64_t B = q.size(0);
  if (q.size(1) != kNumQOHeads) throw std::invalid_argument("q.size(1) must be 32");
  if (q.size(2) != kHeadDim) throw std::invalid_argument("q.size(2) must be 128");

  if (k_cache.size(1) != kPageSize) throw std::invalid_argument("k_cache.size(1) must be 1");
  if (k_cache.size(2) != kNumKVHeads) throw std::invalid_argument("k_cache.size(2) must be 4");
  if (k_cache.size(3) != kHeadDim) throw std::invalid_argument("k_cache.size(3) must be 128");
  if (!v_cache.sizes().equals(k_cache.sizes())) throw std::invalid_argument("v_cache must have same shape as k_cache");

  if (kv_indptr.size(0) != B + 1) throw std::invalid_argument("kv_indptr length must be batch_size+1");

  const auto dev = q.device();
  if (k_cache.device() != dev || v_cache.device() != dev ||
      kv_indptr.device() != dev || kv_indices.device() != dev) {
    throw std::invalid_argument("All inputs must be on the same CUDA device");
  }

  const int64_t num_pages = k_cache.size(0);
  float sm_scale = sm_scale_opt.has_value()
      ? static_cast<float>(*sm_scale_opt)
      : static_cast<float>(1.0 / std::sqrt(static_cast<double>(kHeadDim)));

  auto out = torch::empty({B, kNumQOHeads, kHeadDim},
                          torch::TensorOptions().device(dev).dtype(torch::kBFloat16));
  auto lse = torch::empty({B, kNumQOHeads},
                          torch::TensorOptions().device(dev).dtype(torch::kFloat32));

  c10::cuda::CUDAGuard device_guard(dev);

  // Use PyTorch current stream (do NOT use default stream).
  cudaStream_t stream = at::cuda::getCurrentCUDAStream(dev.index()).stream();

  LaunchGQAPagedDecodeH32KV4D128PS1(
      q.data_ptr(),
      k_cache.data_ptr(),
      v_cache.data_ptr(),
      kv_indptr.data_ptr<int32_t>(),
      kv_indices.data_ptr<int32_t>(),
      static_cast<int32_t>(B),
      static_cast<int32_t>(num_pages),
      sm_scale,
      out.data_ptr(),
      lse.data_ptr<float>(),
      stream);

  // Only check launch error; avoid device synchronize (can be sandbox-hostile).
  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA kernel launch failed: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return {out, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "gqa_paged_decode_h32_kv4_d128_ps1 (CUDA)",
        py::arg("q"),
        py::arg("k_cache"),
        py::arg("v_cache"),
        py::arg("kv_indptr"),
        py::arg("kv_indices"),
        py::arg("sm_scale") = py::none());
}
